/**
 * A single captured media error (name + message only — no PII).
 */
export interface LiveDiagError {
  /** Where it happened (connect|combined|mic|camera|switch|toggle-cam|toggle-mic) */
  stage?: string;
  /** DOMException name (NotAllowedError, NotReadableError, …) */
  name?: string;
  message?: string;
}

/**
 * Client-side media diagnostics for one Live call, used to debug why a device can't capture/publish. Contains NO tokens and no PII beyond the userAgent string.
 */
export interface LiveDiagReport {
  /** What triggered this snapshot (acquire|delayed|teardown) */
  reason?: string;
  /** Whether room.connect() succeeded (separate from getUserMedia) */
  connectOk?: boolean;
  connectError?: LiveDiagError;
  /** How local media was acquired (combined|mic-only|camera-only|failed|none) */
  gumMode?: string;
  cameraAcquired?: boolean;
  micAcquired?: boolean;
  gumErrors?: LiveDiagError[];
  /** LocalTrackPublished fired for the camera track */
  publishedCamera?: boolean;
  /** LocalTrackPublished fired for the mic track */
  publishedMic?: boolean;
  /** Subscribed to the partner's camera track */
  subscribedVideo?: boolean;
  /** Subscribed to the partner's mic track */
  subscribedAudio?: boolean;
  /** enumerateDevices videoinput count before acquisition */
  videoInputsPre?: number;
  audioInputsPre?: number;
  /** enumerateDevices videoinput count after acquisition */
  videoInputsPost?: number;
  audioInputsPost?: number;
  connectionState?: string;
  disconnectReason?: string;
  userAgent?: string;
  isSecureContext?: boolean;
  /** Running as an iOS Home-Screen PWA (navigator.standalone) */
  standalone?: boolean;
  /** navigator.mediaDevices is defined (false in insecure/odd contexts) */
  mediaDevicesPresent?: boolean;
  /** navigator.permissions camera state (granted|denied|prompt|unknown) */
  cameraPermission?: string;
  /** navigator.permissions microphone state */
  micPermission?: string;
  /** videoWidth of the self-view <video> (>0 = local frames decoding) */
  localVideoWidth?: number;
  /** videoWidth of the remote <video> (>0 = remote frames decoding) */
  remoteVideoWidth?: number;
  /** Local camera publication isMuted (published but sending black) */
  cameraPubMuted?: boolean;
  /** Local camera MediaStreamTrack.readyState (live|ended) */
  cameraTrackReadyState?: string;
  /** Local camera MediaStreamTrack.muted (true = producing no frames) */
  cameraTrackMuted?: boolean;
  /** Local camera getSettings().width */
  cameraWidth?: number;
  /** Local camera getSettings().height */
  cameraHeight?: number;
  /** self-view <video>.paused (true = not playing → black on mobile) */
  localVideoPaused?: boolean;
  /** self-view <video>.currentTime (stuck at 0 = never painted a frame) */
  localVideoCurrentTime?: number;
  /** self-view <video>.readyState (0-4; <2 = no current frame) */
  localVideoReadyState?: number;
  /** self-view <video>.clientWidth (0 = laid out with no size → invisible) */
  localClientWidth?: number;
  /** self-view <video>.clientHeight */
  localClientHeight?: number;
  /** DOMException name if the self-view play() promise rejected */
  localPlayError?: string;
  /** remote <video>.paused (true = not playing → black on mobile) */
  remoteVideoPaused?: boolean;
  /** remote <video>.currentTime (stuck at 0 = never painted a frame) */
  remoteVideoCurrentTime?: number;
  /** remote <video>.readyState (0-4; <2 = no current frame) */
  remoteVideoReadyState?: number;
  /** remote <video>.clientWidth (0 = laid out with no size → invisible) */
  remoteClientWidth?: number;
  /** remote <video>.clientHeight */
  remoteClientHeight?: number;
  /** DOMException name if the remote play() promise rejected */
  remotePlayError?: string;
}

